const ethicsResult = JSON.parse($input.first().json.ethics_result);
const evalResult = JSON.parse($('Parse Evaluation').first().json.evaluation_result);
const ideasJson = JSON.parse($('Parse Ideas from Response').first().json.ideas_json);
const timestamp = $input.first().json.timestamp;

const approvedIdeas = (ethicsResult.reviews || ethicsResult.ideas || []).filter(r => r.verdict === 'APPROVED');

const rows = approvedIdeas.map(approved => {
  const idea = ideasJson.find(i => i.name === approved.name) || {};
  const evaluation = (evalResult.evaluations || []).find(e => e.name === approved.name) || {};
  return {
    json: {
      product_name: approved.name || '',
      category: idea.category || '',
      tagline: idea.tagline || '',
      problem: idea.problem || '',
      solution: idea.solution || '',
      target_audience: idea.target_audience || '',
      monthly_price: idea.monthly_price || '',
      key_features: JSON.stringify(idea.key_features || []),
      differentiation: idea.differentiation || '',
      weighted_score: evaluation.weighted_average || evaluation.weighted_score || '',
      ethics_verdict: 'APPROVED',
      ethics_conditions: JSON.stringify(approved.conditions || []),
      status: 'PENDING_APPROVAL',
      research_date: timestamp,
      research_batch_id: 'RB-' + Date.now()
    }
  };
});

return rows.length > 0 ? rows : [{ json: { error: 'No approved ideas', timestamp } }];
